"use strict";parserFactory.register("ultimaguil.org",()=>new UltimaguilParser(new VariableSizeImageCollector));class UltimaguilParser extends Parser{constructor(e){super(e)}getChapterUrls(e){return Promise.resolve(util.hyperlinksToChapterList(e))}extractTitleImpl(e){return"Twintails"}extractAuthor(e){return"Mizusawa Yume"}findContent(e){return e.querySelector("div#inside")}populateUIImpl(){document.getElementById("highestResolutionImagesRow").hidden=!1}webPageToEpubItems(e,t){let r=this.convertRawDomToContent(e),o=[];return null!=r&&(o=this.splitContentIntoEpubItems(r,e.sourceUrl,t)),o}splitContentIntoEpubItems(e,t,r){this.convertMidpartToHeaders(e);let o=BakaTsukiParser.splitContentOnHeadingTags(e);return BakaTsukiParser.itemsToEpubItems(o,r,t)}convertMidpartToHeaders(e){let t=e.ownerDocument;for(let r of e.querySelectorAll("div.part.midpart.gear")){let e=r.parentElement,o=t.createElement("h2"),n=r.querySelector("a");o.appendChild(t.createTextNode(n.getAttribute("title"))),e.replaceWith(o)}}customRawDomToContentStep(e,t){this.flattenContent(t),this.removeLinkFromHeaders(t)}flattenContent(e){let t=e.querySelector("span#read_content");if(null!==t){let e=t.parentElement;for(;t.hasChildNodes();){let r=t.childNodes[0];if("div"===r.tagName.toLowerCase()){let o=r;for(;o.hasChildNodes();)e.insertBefore(o.childNodes[0],t);o.remove()}else e.insertBefore(r,t)}}}removeLinkFromHeaders(e){let t=e.ownerDocument;for(let r of e.querySelectorAll("h2 a"))r.replaceWith(t.createTextNode(r.textContent))}}